import React, { Component } from 'react';
import { Text, Button } from 'react-native';
import { InAppUtils } from 'react-native-iap';
import { PaymentRequest } from 'react-native-payments';

const products = ['com.appname.productId']; //define your product ids (this must match with the id's you set in playstore and appstore)
const paymentMethodData = [{ supportedMethods: 'https://bobpay.com' }]; // Supported payment methods

class PaymentModule extends Component {
    state = {
        errorMessage: '',
        successMessage: '',
    };

    getItems = () => {
        InAppUtils.loadProducts(products, (error, products) => {
            if (error) {
                this.setState({errorMessage: 'Could not load products'});
            }
            else {
                this.setState({products: products})
            }
        });
    };
  
    makePayment = () => {
        const paymentDetails = {
            total: { 
                label: 'Total', 
                amount: { currency: 'USD', value: '10.00' } 
            },
        };
        const paymentRequest = new PaymentRequest(paymentMethodData, paymentDetails);
        paymentRequest.show()
            .then(paymentResponse => {
                 // Handle payment response here
                 paymentResponse.complete('success'); // This is important, it informs the payment provider that everything went well
            })
            .catch(error => this.setState({errorMessage: 'Payment failed'}));
    };

    render() {
        return (
            <>
                <Button
                    title="Get Items"
                    onPress={this.getItems}
                />
                <Button
                    title="Make Payment"
                    onPress={this.makePayment}
                />
                { this.state.errorMessage && <Text>{ this.state.errorMessage }</Text> }
                { this.state.successMessage && <Text>{ this.state.successMessage }</Text> }
            </>
        )
    }
}

export default PaymentModule;